"""
图书管理系统 - 主应用入口
Library Management System - Main Application Entry
"""

from flask import Flask
from flask_sqlalchemy import SQLAlchemy
from flask_migrate import Migrate
from flask_cors import CORS
from flask_jwt_extended import JWTManager
from flask_redis import FlaskRedis
from flask_limiter import Limiter
from flask_limiter.util import get_remote_address
import os
from datetime import timedelta

# 初始化扩展
db = SQLAlchemy()
migrate = Migrate()
jwt = JWTManager()
redis_client = FlaskRedis()
limiter = Limiter(key_func=get_remote_address)

def create_app(config_name='default'):
    """应用工厂函数"""
    app = Flask(__name__)

    # 配置
    app.config['SECRET_KEY'] = os.environ.get('SECRET_KEY', 'library-secret-key-2024')
    app.config['SQLALCHEMY_DATABASE_URI'] = os.environ.get(
        'DATABASE_URL',
        'mysql+pymysql://root:password@localhost:3306/library_db?charset=utf8mb4'
    )
    app.config['SQLALCHEMY_TRACK_MODIFICATIONS'] = False
    app.config['SQLALCHEMY_POOL_SIZE'] = 20
    app.config['SQLALCHEMY_POOL_RECYCLE'] = 3600
    app.config['SQLALCHEMY_MAX_OVERFLOW'] = 10

    # JWT配置
    app.config['JWT_SECRET_KEY'] = os.environ.get('JWT_SECRET_KEY', 'jwt-secret-key-2024')
    app.config['JWT_ACCESS_TOKEN_EXPIRES'] = timedelta(hours=24)
    app.config['JWT_REFRESH_TOKEN_EXPIRES'] = timedelta(days=30)
    app.config['JWT_TOKEN_LOCATION'] = ['headers']
    app.config['JWT_HEADER_NAME'] = 'Authorization'
    app.config['JWT_HEADER_TYPE'] = 'Bearer'

    # Redis配置
    app.config['REDIS_URL'] = os.environ.get('REDIS_URL', 'redis://localhost:6379/0')

    # 上传配置
    app.config['MAX_CONTENT_LENGTH'] = 16 * 1024 * 1024  # 16MB

    # 初始化扩展
    db.init_app(app)
    migrate.init_app(app, db)
    jwt.init_app(app)
    CORS(app, resources={r"/api/*": {"origins": "*"}}, supports_credentials=True)
    redis_client.init_app(app)
    limiter.init_app(app)

    # 注册蓝图
    from routes.auth import auth_bp
    from routes.books import books_bp
    from routes.users import users_bp
    from routes.borrow import borrow_bp

    app.register_blueprint(auth_bp, url_prefix='/api/auth')
    app.register_blueprint(books_bp, url_prefix='/api/books')
    app.register_blueprint(users_bp, url_prefix='/api/users')
    app.register_blueprint(borrow_bp, url_prefix='/api/borrow')

    # 注册错误处理器
    register_error_handlers(app)

    # 注册请求处理器
    register_request_handlers(app)

    return app

def register_error_handlers(app):
    """注册全局错误处理器"""
    from utils.response import api_error

    @app.errorhandler(400)
    def bad_request(error):
        return api_error('请求参数错误', 400)

    @app.errorhandler(401)
    def unauthorized(error):
        return api_error('未授权访问', 401)

    @app.errorhandler(403)
    def forbidden(error):
        return api_error('权限不足', 403)

    @app.errorhandler(404)
    def not_found(error):
        return api_error('资源不存在', 404)

    @app.errorhandler(405)
    def method_not_allowed(error):
        return api_error('请求方法不允许', 405)

    @app.errorhandler(429)
    def too_many_requests(error):
        return api_error('请求过于频繁，请稍后再试', 429)

    @app.errorhandler(500)
    def internal_error(error):
        return api_error('服务器内部错误', 500)

def register_request_handlers(app):
    """注册请求处理器（SQL注入过滤、XSS防护）"""
    from utils.filters import sanitize_input

    @app.before_request
    def before_request():
        # 过滤查询参数
        from flask import request
        if request.args:
            for key, value in request.args.items():
                sanitize_input(value)
        if request.json:
            for key, value in request.json.items():
                if isinstance(value, str):
                    request.json[key] = sanitize_input(value)

if __name__ == '__main__':
    app = create_app()
    with app.app_context():
        db.create_all()
    app.run(host='0.0.0.0', port=5000, debug=True)
